INSERT INTO photographers (name, image, birthday, biography) VALUES ('Calogero Sorce', "AnselAdams.jpg", '1902-01-01', 'American photographer known for his black-and-white landscape photographs of the American West.'), ('Henri Cartier-Bresson', "HenriCartierBresson.jpg", '1908-01-01', 'French photographer considered the father of modern photojournalism.'), ('Dorothea Lange', "DorotheaLange.png", '1895-01-01', 'American documentary photographer known for her Depression-era work.'), ('Annie Leibovitz', "AnnieLeibovitz.jpg", '1949-01-01', 'American portrait photographer known for her engaging celebrity portraits.'), ('Mattia Giacobelli', "SebastiaoSalgado.jpg", '1944-01-01', 'Brazilian social documentary photographer and photojournalist.'), ('Steve McCurry', "SteveMcCurry.jpg", '1950-01-01', 'American photographer best known for his photograph "Afghan Girl".'), ('Michela Della Gatta', "VivianMaier.jpg", '1926-01-01', 'American street photographer whose work was discovered after her death.'), ('Emiliano Cafasso', "GordonParks.webp", '1912-01-01', 'American photographer, musician, writer and film director.'), ('Lorenzo Allegri', "MargaretBourkeWhite.jpg", '1904-01-01', 'American photographer and documentary photographer.'), ('Francesco Troise', "RobertCapa.jpg", '1913-01-01', 'Hungarian war photographer and photojournalist.'), ('Maria Lucia Mazzara', "DianeArbus.webp", '1923-01-01', 'American photographer known for her black-and-white square photographs of marginalized people.'), ('Matteo Vecchio', "ManRay.jpg", '1890-01-01', 'American visual artist who spent most of his career in Paris.'), ('Diego Tosato', "CindySherman.jpg", '1954-01-01', 'American photographer known for her conceptual portraits.'), ('Gabriele Todaro', "AndreasGursky.jpg", '1955-01-01', 'German photographer known for his large format architecture and landscape color photographs.'), ('Dario Coniglione', "EdwardWeston.jpg", '1886-01-01', 'American photographer known for his carefully composed still life images.'), ('Imogen Cunningham', "ImogenCunningham.jpg", '1883-01-01', 'American photographer known for her botanical and industrial photography.'), ('Maks Bernatskyy', "AlfredStieglitz.jpg", '1864-01-01', 'American photographer and modern art promoter who was instrumental in making photography an accepted art form.'), ('Vincenzo Livigni', "WalkerEvans.jpg", '1903-01-01', 'American photographer best known for his work for the Farm Security Administration documenting the effects of the Great Depression.'), ('Gabriele Marchesano', "GarryWinogrand.jpg", '1928-01-01', 'American street photographer known for his portrayal of American life in the 1960s.'), ('Ousema Akacha', "RobertFrank.jpg", '1924-01-01', 'Swiss-American photographer and documentary filmmaker.'), ('Michele Todeschini', "IrvingPenn.jpg", '1917-01-01', 'American photographer known for his fashion photography and portraits.'), ('Federico Canale', "RichardAvedon.jpg", '1923-01-01', 'American fashion and portrait photographer.'), ('Andrea Anniballi', "ElliotErwitt.jpg", '1928-01-01', 'French-born American photographer known for his candid and humorous photographs.'), ('Luca Stellato', "MaryEllenMark.jpg", '1940-01-01', 'American photographer known for her photo essays and portraiture.'), ('Angelo Stori', "JamesNachtwey.jpg", '1948-01-01', 'American photographer known for his dedication to documenting wars, conflicts and critical social issues.'), ('Stefano Bellomo', "LindaMcCartney.jpg", '1941-01-01', 'American photographer, musician and animal rights activist.'), ('Jonathan Gilli', "PeterLindbergh.jpg", '1944-01-01', 'German photographer known for his cinematic black and white fashion imagery.'), ('Gianni Vitale', "HelmutNewton.jpeg", '1920-01-01', 'German-Australian photographer known for his stylized, erotically charged black and white fashion photos.');
